// Validate + dedupe + build message for Paperclip Watch Alert workflow.
//
// Input: webhook JSON body with shape
//   { alert_type, correlation_id, as_of, market, triggered:[{symbol,condition_type,threshold,current}], message }
// Output (single item) with `route` keyed by the Switch node:
//   route = 'invalid' | 'deduped' | 'crypto' | 'kr' | 'us'
//
// IMPORTANT: sentMap is only READ here. The actual write happens in the `Mark Sent`
// code node AFTER Discord delivery succeeds, so a Discord 5xx → auto_trader retry
// can re-evaluate the payload and re-deliver instead of silently deduping.
const input = $input.first().json || {};
const body = (input.body && typeof input.body === 'object') ? input.body : input;

const staticData = $getWorkflowStaticData('global');
if (!staticData.sentMap || typeof staticData.sentMap !== 'object') staticData.sentMap = {};
const sentMap = staticData.sentMap;

const nowMs = Date.now();
const COOLDOWN_MS = 6 * 60 * 60 * 1000;
const GC_AGE_MS = 24 * 60 * 60 * 1000;
const ALLOWED_MARKETS = ['crypto', 'kr', 'us'];

// GC entries older than 24h so the static map does not grow unbounded.
for (const key of Object.keys(sentMap)) {
  const entry = sentMap[key];
  if (!entry || typeof entry !== 'object') {
    delete sentMap[key];
    continue;
  }
  const lastSentAt = Number(entry.lastSentAt || 0);
  if (!lastSentAt || (nowMs - lastSentAt) > GC_AGE_MS) delete sentMap[key];
}

const correlationId = typeof body.correlation_id === 'string' ? body.correlation_id : null;
const asOf = typeof body.as_of === 'string' ? body.as_of : null;
const market = String(body.market || '').trim().toLowerCase();
const triggered = Array.isArray(body.triggered) ? body.triggered : null;
const rawMessage = typeof body.message === 'string' ? body.message : '';

function invalid(errorCode, detail) {
  return [{
    json: {
      route: 'invalid',
      errorCode,
      detail: detail || null,
      market: market || null,
      correlationId,
      asOf,
      responseStatusCode: 400,
      responseBody: JSON.stringify({
        status: 'error',
        error: errorCode,
        detail: detail || null,
        correlation_id: correlationId,
      }),
    },
  }];
}

if (!ALLOWED_MARKETS.includes(market)) {
  return invalid('unknown_market', `market must be one of ${ALLOWED_MARKETS.join(', ')}`);
}
if (!triggered || triggered.length === 0) {
  return invalid('missing_triggered', 'triggered array is required and must be non-empty');
}

for (const item of triggered) {
  if (!item || typeof item !== 'object') {
    return invalid('invalid_triggered_item', 'each triggered entry must be an object');
  }
  if (!item.symbol || !item.condition_type || item.threshold === undefined || item.threshold === null) {
    return invalid('invalid_triggered_item', 'symbol/condition_type/threshold are required per item');
  }
  const thresholdType = typeof item.threshold;
  if (thresholdType !== 'number' && thresholdType !== 'string') {
    return invalid('invalid_triggered_item', 'threshold must be a number or string');
  }
}

let newItemCount = 0;
const fingerprints = triggered.map((item) => {
  const symbol = String(item.symbol).trim();
  const conditionType = String(item.condition_type).trim();
  const threshold = item.threshold;
  const fp = `${market}:${symbol}:${conditionType}:${threshold}`;
  const previous = sentMap[fp];
  const lastSentAt = previous && typeof previous === 'object' ? Number(previous.lastSentAt || 0) : 0;
  const isNew = !lastSentAt || (nowMs - lastSentAt) > COOLDOWN_MS;
  if (isNew) newItemCount += 1;
  return { fp, isNew };
});

const dedupedCount = fingerprints.length - newItemCount;

if (newItemCount === 0) {
  // Every triggered item is inside the 6h cooldown — noop but still 200.
  // No sentMap write here: entries already have lastSentAt recorded from the
  // prior successful delivery.
  return [{
    json: {
      route: 'deduped',
      market,
      correlationId,
      asOf,
      sentCount: 0,
      dedupedCount,
      fingerprints,
      responseStatusCode: 200,
      responseBody: JSON.stringify({
        status: 'deduped',
        market,
        sent_count: 0,
        deduped_count: dedupedCount,
        correlation_id: correlationId,
      }),
    },
  }];
}

const footer = `\n\ncorrelation_id=${correlationId || 'unknown'}  as_of=${asOf || 'unknown'}`;
const discordContent = rawMessage ? `${rawMessage}${footer}` : `Watch alert (${market})${footer}`;

return [{
  json: {
    route: market,
    market,
    correlationId,
    asOf,
    sentCount: newItemCount,
    dedupedCount,
    discordContent,
    fingerprints,
    responseStatusCode: 200,
    responseBody: JSON.stringify({
      status: 'sent',
      market,
      sent_count: newItemCount,
      deduped_count: dedupedCount,
      correlation_id: correlationId,
    }),
  },
}];

// Record fingerprint send times AFTER Discord delivery succeeds.
// This runs only on the Discord main (success) output path, so a Discord 5xx
// routes around this node into `Respond 500` and leaves sentMap untouched,
// letting auto_trader retry re-deliver the alert.
const upstream = $('Validate & Dedupe').item.json || {};
const fingerprints = Array.isArray(upstream.fingerprints) ? upstream.fingerprints : [];
const nowMs = Date.now();

const staticData = $getWorkflowStaticData('global');
if (!staticData.sentMap || typeof staticData.sentMap !== 'object') staticData.sentMap = {};
const sentMap = staticData.sentMap;

// Refresh every fingerprint in the payload (new + re-mentioned) so the user
// does not re-receive the same alert inside the 6h cooldown.
for (const entry of fingerprints) {
  if (!entry || typeof entry !== 'object' || !entry.fp) continue;
  sentMap[entry.fp] = { lastSentAt: nowMs };
}

return $input.all();
